BoxConfig = {}
BoxConfig.Boxes = {}

function BoxConfig:init(config)
    for id, box in pairs(config) do
        local item = {}
        item.id = box.id
        local pos = StringUtil.split(box.pos, "#")
        item.pos = VectorUtil.newVector3(tonumber(pos[1]), tonumber(pos[2]), tonumber(pos[3]))
        item.yaw = tonumber(pos[4])
        item.pool1 = StringUtil.split(box.pool1, "#")
        item.num1 = StringUtil.split(box.num1, "#")
        item.pool2 = StringUtil.split(box.pool2, "#")
        item.num2 = StringUtil.split(box.num2, "#")
        item.pool3 = StringUtil.split(box.pool3, "#")
        item.num3 = StringUtil.split(box.num3, "#")
        self.Boxes[item.id] = item
    end
end

function BoxConfig:getBoxes()
    local result = TableUtil.copyTable(self.Boxes)
    return result
end

return BoxConfig